'use client';

import { create } from 'zustand';
import { persist } from 'zustand/middleware';

export const useStore = create(
  persist(
    (set, get) => ({
      members: [],          // শুরুতে কোনো মেম্বার নেই
      transactions: [],     // সব লেনদেন এখানে

      addMember: (data) => 
        set(state => ({
          members: [
            ...state.members,
            {
              id: Date.now().toString(),
              name: data.name.trim(),
              phone: data.phone?.trim() || '',
              address: data.address?.trim() || '',
              avatar: data.avatar?.trim() || `https://i.pravatar.cc/150?u=${encodeURIComponent(data.name)}`,
              type: data.type || 'both', // 'donor', 'receiver', 'both'
              totalDonated: 0,
              totalReceived: 0,
              notes: data.notes?.trim() || ''
            }
          ]
        })),

      updateMemberTotals: (memberId, donated = 0, received = 0) =>
        set(state => ({
          members: state.members.map(m =>
            m.id === memberId
              ? {
                  ...m,
                  totalDonated: (m.totalDonated || 0) + donated,
                  totalReceived: (m.totalReceived || 0) + received
                }
              : m
          )
        })),

      addTransaction: (tx) =>
        set(state => {
          const newTx = {
            ...tx,
            id: Date.now().toString(),
            date: new Date().toISOString().split('T')[0]
          };

          // টোটাল আপডেট
          if (tx.type === 'donation') {
            if (tx.donorId) state.updateMemberTotals(tx.donorId, tx.amount, 0);
            if (tx.receiverId) state.updateMemberTotals(tx.receiverId, 0, tx.amount);
          }

          return { transactions: [...state.transactions, newTx] };
        }),

      deleteTransaction: (id) =>
        set(state => ({
          transactions: state.transactions.filter(t => t.id !== id)
        })),

      searchMembers: (query = '') =>
        get().members.filter(m =>
          m.name.toLowerCase().includes(query.toLowerCase()) ||
          (m.phone && m.phone.includes(query))
        ),

      get totalDonation() {
        return get().transactions
          .filter(t => t.type === 'donation')
          .reduce((sum, t) => sum + (t.amount || 0), 0);
      },

      get totalExpense() {
        return get().transactions
          .filter(t => t.type === 'expense')
          .reduce((sum, t) => sum + (t.amount || 0), 0);
      },

      get netBalance() {
        return get().totalDonation - get().totalExpense;
      }
    }),
    {
      name: 'community-fund-db-2026'
    }
  )
);