'use client';
import { useState } from 'react';
import { useStore } from '../lib/store';

export default function Dashboard() {
  const [isLogged, setIsLogged] = useState(false);
  const [pass, setPass] = useState('');

  // সব হুক একদম উপরে
  const [newMemberName, setNewMemberName] = useState('');
  const [newMemberPhone, setNewMemberPhone] = useState('');
  const [newMemberAddress, setNewMemberAddress] = useState('');
  const [newMemberAvatar, setNewMemberAvatar] = useState('');

  const { members, addMember } = useStore();

  const handleLogin = () => {
    if (pass === 'admin123') {
      setIsLogged(true);
      setPass('');
    } else {
      alert('ভুল পাসওয়ার্ড!');
    }
  };

  const handleAddMember = () => {
    if (!newMemberName.trim()) {
      alert('নাম দিন!');
      return;
    }

    addMember({
      name: newMemberName.trim(),
      phone: newMemberPhone.trim(),
      address: newMemberAddress.trim(),
      avatar: newMemberAvatar.trim() || `https://i.pravatar.cc/150?u=${encodeURIComponent(newMemberName)}`,
    });

    // ফর্ম ক্লিয়ার
    setNewMemberName('');
    setNewMemberPhone('');
    setNewMemberAddress('');
    setNewMemberAvatar('');

    alert('সদস্য যোগ হয়েছে!');
  };

  if (!isLogged) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-900">
        <div className="bg-white p-10 rounded-3xl shadow-2xl max-w-md w-full text-center">
          <h1 className="text-4xl font-bold mb-6">অ্যাডমিন লগইন</h1>
          <input
            type="password"
            placeholder="পাসওয়ার্ড"
            value={pass}
            onChange={(e) => setPass(e.target.value)}
            className="border p-4 rounded-xl w-full text-xl mb-4 text-black"
          />
          <button
            onClick={handleLogin}
            className="bg-emerald-600 text-white px-10 py-4 rounded-xl text-xl w-full"
          >
            লগইন
          </button>
          <p className="text-sm text-gray-500 mt-4">demo: admin123</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 p-10">
      <div className="max-w-4xl mx-auto bg-white rounded-3xl shadow-2xl p-10">
        <h1 className="text-4xl font-bold text-center mb-10 text-emerald-800">
          অ্যাডমিন ড্যাশবোর্ড
        </h1>

        <h2 className="text-3xl font-bold mb-6">নতুন সদস্য যোগ করুন</h2>

        <div className="space-y-4">
          <input
            placeholder="নাম (আবশ্যক)"
            value={newMemberName}
            onChange={(e) => setNewMemberName(e.target.value)}
            className="border p-4 rounded-xl w-full text-black"
          />
          <input
            placeholder="ফোন নম্বর"
            value={newMemberPhone}
            onChange={(e) => setNewMemberPhone(e.target.value)}
            className="border p-4 rounded-xl w-full text-black"
          />
          <input
            placeholder="ঠিকানা"
            value={newMemberAddress}
            onChange={(e) => setNewMemberAddress(e.target.value)}
            className="border p-4 rounded-xl w-full text-black"
          />
          <input
            placeholder="ছবির URL (optional)"
            value={newMemberAvatar}
            onChange={(e) => setNewMemberAvatar(e.target.value)}
            className="border p-4 rounded-xl w-full text-black"
          />

          <button
            onClick={handleAddMember}
            className="bg-emerald-600 hover:bg-emerald-700 text-white px-10 py-5 rounded-xl font-bold w-full mt-4 text-xl transition"
          >
            সদস্য যোগ করুন
          </button>
        </div>

        <h2 className="text-3xl font-bold mt-16 mb-6">সকল সদস্য ({members.length})</h2>

        {members.length === 0 ? (
          <p className="text-center text-gray-600 text-xl py-10">
            এখনো কোনো সদস্য যোগ করা হয়নি
          </p>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {members.map((m) => (
              <div key={m.id} className="bg-gray-100 p-6 rounded-2xl shadow">
                <h3 className="text-xl font-bold">{m.name}</h3>
                {m.phone && <p>ফোন: {m.phone}</p>}
                {m.address && <p>ঠিকানা: {m.address}</p>}
                {m.avatar && (
                  <img
                    src={m.avatar}
                    alt={m.name}
                    className="w-20 h-20 rounded-full mx-auto mt-4 object-cover"
                  />
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}